mapper.select:
SELECT 
FROM product_account pa
LEFT JOIN shop_product p ON p.id = pa.product_id
LEFT JOIN shop_order o ON o.id = pa.assigned_order_id
WHERE pa.resource_type = 'CARD_KEY'

    AND pa.product_id = #{productId}


    AND pa.sale_status = #{saleStatus}


    AND pa.enable_status = #{enableStatus}


    AND pa.used_status = #{usedStatus}


    AND (
        p.title LIKE CONCAT(#{keyword}, '%')
        OR pa.account_name_masked LIKE CONCAT(#{keyword}, '%')
        OR o.order_no = #{keyword}
        OR o.order_no LIKE CONCAT(#{keyword}, '%')
    )


    AND (
        pa.created_at < #{cursorCreatedAt}
        OR (pa.created_at = #{cursorCreatedAt} AND pa.id < #{cursorId})
    )

ORDER BY pa.created_at DESC, pa.id DESC
LIMIT #{limit}

SELECT 
FROM product_account
WHERE product_id = #{productId}
  AND allocation_handle IN

    #{handle}

